var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"역시 소문대로 직원 분들의 일처리가 깔끔하군요.","JPN":"噂どおり、御社の仕事ぶりはお見事ですね。","ENG":"So I see it's true that you have a very capable team of employees.","TWN":"果然，各位員工如傳聞一樣，辦事乾淨俐落啊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 정도 소재라면 충분한 샘플을 배포할 수 있겠어요.","JPN":"これぐらい素材があれば十分なサンプルを配布できそうです。","ENG":"This would suffice to make enough samples for demonstration.","TWN":"這麼多素材，完全足夠分發樣品了呢。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"지금쯤 이런 의문이 드시겠군요.","JPN":"今頃こういった疑問が浮かんでいることでしょう。","ENG":"There's a question rising in your mind, isn't there?","TWN":"這時候你應該有了這個疑問吧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"어차피 장비는 침식체 몸속의 이터니움을 추출해서 만들지 않나?","JPN":"どうせ装備は侵食体の体内のエタニウムを抽出して作るのだろう。","ENG":"Gear and equipment are primarily made from Eternium extracted from Corrupted Objects.","TWN":"反正製作裝備只需要萃取侵蝕體體內的永恆之金不是嗎？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 왜 이 회사는 무겁고 쓸모도 없는 침식체를 통째로 보내달라고 한 거지?","JPN":"なのに、なぜこの会社はただ重いだけで使い道もない侵食体をそのまま丸ごと送ってほしいと言うんだ、と。","ENG":"What are they planning to do with these large, unprocessed Corrupted Objects?","TWN":"但這個公司為什麼要我們把重而無用的整只侵蝕體都送去？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 이유는 간단합니다.","JPN":"ハハハ、理由は簡単です。","ENG":"Hah hah, the answer is simple.","TWN":"哈哈，理由很簡單。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"저희는 원하는 신소재는 이터니움이 아닌 침식체 자체이기 때문이죠.","JPN":"弊社が求める新素材はエタニウムではなく、侵食体そのものなのです。","ENG":"It's not Eternium, but the body of a Corrupted Object itself that we want to use as material.","TWN":"因為我們需要的新素材不是能晶，而是侵蝕體本身。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"저희 아이언 테일러는 예전부터 침식체의 외피가 가진 경이로운 내구성에 주목해왔습니다.","JPN":"アイアンテイラーは以前から侵食体の外皮の持つ驚異的な耐久性に注目してきました。","ENG":"The Iron Tailors have been trying to find a way to utilize the phenomenal durability of Corrupted Objects's outer shell.","TWN":"因為侵蝕體的外皮有驚人的耐久性，所以我們鋼鐵泰勒從很久之前就一直對此有所關注。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"철갑탄을 튕겨내고 불에 타지 않는 침식체의 갑옷을 우리 인간이 입을 수만 있다면, 인류 역전의 발판이 되지 않을까 하고 말이죠!","JPN":"徹甲弾すら弾き飛ばし、燃えることのない侵食体の鎧を我々人間が着ることさえできれば、人類逆転の足掛かりになるのではないか、と。","ENG":"What if the mankind could use the bullet-reflecting, fire-resisting integument of Corrupted Objects as armor? Wouldn't it change everything for us?","TWN":"侵蝕體的鎧甲可以反彈穿甲彈，又可以防火，人類只要能穿上它，一定可以逆轉局勢！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 오랜 연구와 투자 끝에, 저희는 결국 해내고야 말았습니다.","JPN":"そして長年の研究と投資の末、我々はついにやり遂げました。","ENG":"So, through long research and pouring money into the bottomless pit, we did it.","TWN":"經過了長久的研究和投資，我們終於成功了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체는 죽는 순간 몸 전체가 산화반응을 일으켜 한 시간 이내로 원자구조의 95%가 붕괴되기 때문에 소재로 사용할 수 없다는 것이 통상의 이론이지만......","JPN":"侵食体は死ぬ瞬間、体全体が酸化反応を起こし1時間以内に原子構造の95％が崩壊するため、素材として使えないというのが通常の理論ではありますが……","ENG":"It's well known that the body of a Corrupted Object starts to oxidize upon death, with 95% of its atomic structure collapsing within just an hour. This was why it was impossible to process them.","TWN":"侵蝕體死亡的瞬間，其身體會產生氧化反應，在一小時內原子構造的95%就會遭破壞，所以一般來講是無法作為素材使用的……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 개발한 신소재 가공법을 통하면 침식체의 외피를 반영구적으로 보존할 수 있게 됩니다.","JPN":"弊社が開発した新素材加工法を適用すれば、侵食体の外皮を半永久的に保存できるようになります。","ENG":"But through this new method we devised, their outer shell can be preserved, semi-permanently.","TWN":"但是通過我們開發的新素材加工法，可以半永久地保存侵蝕體外皮。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 정말 굉장하지 않습니까? 눈이 휘둥그래지신 사장님의 모습이 훤히 보이는군요.","JPN":"ハハハ、凄いと思いませんか？　今頃目を見張っている社長の顔が目に浮かびます。","ENG":"How great is that? Ah, I can almost see you all wide-eyed and surprised.","TWN":"哈哈，真的很厲害對吧？可以預想睜大眼睛的老闆的樣子了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 지갑은 잠시 넣어두시죠.","JPN":"しかし、財布を取り出すのはもう少し我慢していただきたいです。","ENG":"But I'm afraid you'll have to wait until you open your wallet.","TWN":"不過請暫時放下錢包吧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"안정성 검증이니 뭐니 하는 도시관리국의 쓸데 없는 절차 때문에 아직 판매가 미뤄지고 있거든요.","JPN":"安定性検証だの何だのと都市管理局の無駄な手続きのせいで、まだ販売が先延ばしになっている状況です。","ENG":"Product launch is being delayed with safety tests and all the other pointless procedures by the City Management.","TWN":"因為城市管理局那些安全性檢驗之類的多餘程序，現在產品販賣還在被推遲。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"곧 좋은 소식이 있을 테니 연락 드리겠습니다.","JPN":"もうじき良いお知らせができると思いますので、またご連絡します。","ENG":"But we're expecting good news soon. I'll make sure to keep you informed.","TWN":"一定很快就會有好消息的，到時我會聯繫您。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};